/* SweetAlert minimal stub */
var swal = function(arg1, arg2, arg3) {
    if (typeof arg1 === 'object') {
        var msg = arg1.title || '';
        if (arg1.text) msg += '\n' + arg1.text;
        
        if (arg1.buttons || arg1.showCancelButton) {
            var res = confirm(msg);
            return { then: function(cb) { cb(res); return { catch: function(){} }; } };
        } else {
            alert(msg);
            return { then: function(cb) { cb(true); return { catch: function(){} }; } };
        }
    }
    alert(arg1 + '\n' + (arg2 || ''));
    return { then: function(cb) { cb(true); return { catch: function(){} }; } };
};

swal.fire = function(config) {
    if (typeof config === 'object') {
        alert(config.title + '\n' + (config.text || ''));
    }
};

swal.success = function(title, message) {
    alert(title + '\n' + (message || ''));
};

swal.error = function(title, message) {
    alert(title + '\n' + (message || ''));
};

swal.warning = function(title, message) {
    alert(title + '\n' + (message || ''));
};

swal.info = function(title, message) {
    alert(title + '\n' + (message || ''));
};

swal.confirm = function(title, callback) {
    if (confirm(title)) {
        if (callback) callback();
    }
};
